svg.script:
(function(){
 var NS="http://www.w3.org/2000/svg";
 var svg=document.getElementById('ctroot');
 function mk(t,a,p){var e=document.createElementNS(NS,t);if(a)for(var k in a)e.setAttribute(k,a[k]);if(p)p.appendChild(e);return e;}
 function tx(a,s,p){var e=mk('text',a,p);e.textContent=s;return e;}
 function clr(g){while(g.firstChild)g.removeChild(g.firstChild);}

 var DEG=Math.PI/180, NV=12, DA=15;
 var GREEN='#2f9e44',GD='#1b6b34',GL='#b2f2bb',YEL='#ffd000',AMB='#f08c00',RED='#e03131',INK='#1d2b22',MUT='#5c6b62';
 var C1='#22b8cf', C2='#ff922b';
 var circ=[{x:-34,y:30,r:13,c:C1,n:'①'},{x:36,y:-24,r:13,c:C2,n:'②'}];
 var P1x=214,P1y=250, P3x=1064,P3y=250, R=124, HALF=100;
 function tval(c,th){return c.x*Math.cos(th)+c.y*Math.sin(th);}

 var state=0; // 0=準備 / 1..12=各ビュー / 13=完成

 // ---------- background ----------
 mk('rect',{x:0,y:0,width:1280,height:660,fill:'#f5f8f5'},svg);

 // ---------- panels ----------
 function panel(x,w,title,sub,accent){
   mk('rect',{x:x,y:46,width:w,height:398,rx:14,fill:'#ffffff',stroke:accent,'stroke-width':2.2},svg);
   mk('rect',{x:x,y:46,width:6,height:398,rx:3,fill:accent},svg);
   tx({x:x+20,y:78,'font-size':19,'font-weight':700,fill:accent},title,svg);
   tx({x:x+20,y:98,'font-size':12.5,fill:MUT},sub,svg);
   mk('line',{x1:x+18,y1:106,x2:x+w-18,y2:106,stroke:accent,'stroke-width':1,opacity:.5},svg);
 }
 panel(22,385,'1. 原画像','明るい円2個から投影を取得',GREEN);
 panel(447,385,'2. 各方向の投影データ','角度ごとの 1次元プロファイル p(t)',GREEN);
 panel(872,385,'3. 逆投影して加算','投影値を撮影方向へ帯状に塗り戻す',AMB);

 var a1=tx({x:392,y:78,'font-size':16,'font-weight':700,fill:GD,'text-anchor':'end'},'θ = 0°',svg);
 var a2=tx({x:817,y:78,'font-size':16,'font-weight':700,fill:GD,'text-anchor':'end'},'θ = 0°',svg);
 var p3count=tx({x:1237,y:78,'font-size':16,'font-weight':700,fill:AMB,'text-anchor':'end'},'加算 0 / 12',svg);

 function imgSquare(cx){mk('rect',{x:cx-95,y:155,width:190,height:190,rx:4,fill:'#0a0a0a',stroke:'#000','stroke-width':1},svg);}

 // ---------- panel 1 : original image (fixed) + rotating beam ----------
 imgSquare(P1x);
 circ.forEach(function(c){
   mk('circle',{cx:P1x+c.x,cy:P1y-c.y,r:c.r,fill:'url(#glow)'},svg);
   mk('circle',{cx:P1x+c.x,cy:P1y-c.y,r:c.r,fill:'none',stroke:c.c,'stroke-width':2},svg);
   tx({x:P1x+c.x,y:P1y-c.y-c.r-5,'font-size':13,'font-weight':700,fill:c.c,'text-anchor':'middle'},c.n,svg);
 });
 var gBeam1=mk('g',{},svg);

 // ---------- panel 3 : back-projection accumulation ----------
 imgSquare(P3x);
 var clipWrap=mk('g',{'clip-path':'url(#clip3)'},svg);
 var gAccum=mk('g',{filter:'url(#soft)'},clipWrap);
 var gHi=mk('g',{},clipWrap);
 mk('rect',{x:969,y:155,width:190,height:190,rx:4,fill:'none',stroke:'#2b2b2b','stroke-width':1},svg);
 var p3status=tx({x:P3x,y:372,'font-size':12.5,fill:MUT,'text-anchor':'middle'},'',svg);

 // ---------- panel 2 : projection profile ----------
 var plotX0=470,plotX1=810,yBase=300;
 function Xt(t){return plotX0+(t+95)/190*(plotX1-plotX0);}
 function Yv(v){return yBase-Math.min(v,1.85)*100;}
 mk('line',{x1:plotX0-6,y1:yBase,x2:plotX1+8,y2:yBase,stroke:'#adb5bd','stroke-width':1.4},svg);
 mk('line',{x1:plotX0,y1:yBase+6,x2:plotX0,y2:115,stroke:'#adb5bd','stroke-width':1.4},svg);
 [-95,0,95].forEach(function(t){mk('line',{x1:Xt(t),y1:yBase,x2:Xt(t),y2:yBase+5,stroke:'#adb5bd','stroke-width':1},svg);});
 tx({x:Xt(0),y:yBase+19,'font-size':11.5,fill:MUT,'text-anchor':'middle'},'0',svg);
 tx({x:plotX1+8,y:yBase+19,'font-size':12,fill:MUT,'text-anchor':'end'},'検出器位置 t →',svg);
 tx({x:plotX0-6,y:124,'font-size':12,fill:MUT,'text-anchor':'start'},'投影値 p',svg);
 var gProf=mk('g',{},svg);
 var gPk=mk('g',{},svg);

 // angle buttons (processed indicator + direct select)
 tx({x:455,y:344,'font-size':12.5,'font-weight':700,fill:GD},'処理済みの投影角度（クリックで直接選択）',svg);
 var btns=[];
 for(var i=0;i<NV;i++){
   var bx=455+i*31;
   var g=mk('g',{'class':'btn'},svg);
   var br=mk('rect',{x:bx,y:356,width:27,height:30,rx:6,fill:'#ffffff',stroke:GL,'stroke-width':1.5},g);
   var bt=tx({x:bx+13.5,y:376,'font-size':12,'font-weight':700,fill:GREEN,'text-anchor':'middle'},String(i*DA),g);
   (function(idx){g.addEventListener('click',function(){setState(idx+1);});})(i);
   btns.push({r:br,t:bt});
 }
 tx({x:455,y:404,'font-size':11.5,fill:MUT},'単位：度（°） ・ 0°～165°を 15°刻み',svg);

 // ---------- red connecting arrows ----------
 function arrow(x1,x2,y,label){
   mk('line',{x1:x1,y1:y,x2:x2-11,y2:y,stroke:RED,'stroke-width':4,'stroke-linecap':'round'},svg);
   mk('polygon',{points:x2+','+y+' '+(x2-15)+','+(y-8)+' '+(x2-15)+','+(y+8),fill:RED},svg);
   tx({x:(x1+x2)/2,y:y-13,'font-size':13,'font-weight':700,fill:RED,'text-anchor':'middle'},label,svg);
 }
 arrow(410,444,250,'投影');
 arrow(835,869,250,'逆投影');

 // ---------- control strip ----------
 mk('line',{x1:22,y1:462,x2:1258,y2:462,stroke:'#dde3dd','stroke-width':1},svg);
 var readout=tx({x:640,y:492,'font-size':20,'font-weight':700,fill:GD,'text-anchor':'middle'},'',svg);
 function ctlBtn(x,w,label,fill,stroke,fg){
   var g=mk('g',{'class':'btn'},svg);
   mk('rect',{x:x,y:512,width:w,height:44,rx:10,fill:fill,stroke:stroke,'stroke-width':2},g);
   tx({x:x+w/2,y:540,'font-size':17,'font-weight':700,fill:fg,'text-anchor':'middle'},label,g);
   return g;
 }
 var bPrev=ctlBtn(402,158,'◀ 前のビュー','#ffffff',GREEN,GREEN);
 var bNext=ctlBtn(575,158,'次のビュー ▶',GREEN,GD,'#ffffff');
 var bReset=ctlBtn(748,130,'リセット','#ffffff',RED,RED);
 bPrev.addEventListener('click',function(){setState(state-1);});
 bNext.addEventListener('click',function(){setState(state+1);});
 bReset.addEventListener('click',function(){setState(0);});
 tx({x:640,y:586,'font-size':13.5,fill:MUT,'text-anchor':'middle'},'クリック ／ ← → キーで前後移動 ／ 角度ボタンで直接ジャンプ ／ リセットで準備状態へ',svg);

 // ---------- dynamic drawing ----------
 function drawBeam(idx,dim){
   clr(gBeam1);
   var deg=idx*DA, th=deg*DEG;
   var g=mk('g',{transform:'translate('+P1x+' '+P1y+') rotate('+(-deg)+')',opacity:dim?0.4:1},gBeam1);
   mk('rect',{x:-95,y:-R,width:190,height:2*R,fill:GREEN,opacity:.10},g);
   for(var k=0;k<7;k++){var x=-90+k*30;mk('line',{x1:x,y1:-R,x2:x,y2:R,stroke:GREEN,'stroke-width':1,opacity:.22},g);}
   [-60,0,60].forEach(function(x){mk('polygon',{points:x+',8 '+(x-5)+',-3 '+(x+5)+',-3',fill:GREEN,opacity:.5},g);});
   circ.forEach(function(c){
     var t0=tval(c,th);
     mk('line',{x1:t0,y1:-R,x2:t0,y2:R,stroke:c.c,'stroke-width':2.4,opacity:.92},g);
     mk('circle',{cx:t0,cy:R,r:5,fill:c.c,stroke:'#fff','stroke-width':1.2},g);
   });
   mk('rect',{x:-HALF,y:-R-11,width:2*HALF,height:9,rx:3,fill:GD},g);
   mk('rect',{x:-HALF-8,y:R+2,width:2*HALF+16,height:10,rx:2,fill:'#343a40'},g);
   for(var d=0;d<=12;d++){var xd=-HALF+d*(2*HALF/12);mk('line',{x1:xd,y1:R+2,x2:xd,y2:R+12,stroke:'#868e96','stroke-width':.8},g);}
   tx({x:0,y:-R-17,'font-size':12.5,'font-weight':700,fill:GD,'text-anchor':'middle',transform:'rotate('+deg+',0,'+(-R-17)+')'},'X線源',g);
   tx({x:0,y:R+27,'font-size':12.5,'font-weight':700,fill:'#343a40','text-anchor':'middle',transform:'rotate('+deg+',0,'+(R+27)+')'},'検出器',g);
 }

 function drawProfile(idx,dim){
   clr(gProf);clr(gPk);
   var th=idx*DA*DEG;
   var t0s=circ.map(function(c){return tval(c,th);});
   function val(t){var v=0;for(var j=0;j<circ.length;j++){var d=t-t0s[j];v+=Math.exp(-d*d/162);}return v;}
   var dp='M '+Xt(-95).toFixed(1)+' '+yBase;
   for(var t=-95;t<=95;t+=2){dp+=' L '+Xt(t).toFixed(1)+' '+Yv(val(t)).toFixed(1);}
   dp+=' L '+Xt(95).toFixed(1)+' '+yBase+' Z';
   mk('path',{d:dp,fill:GREEN,'fill-opacity':dim?0.16:0.32,stroke:GREEN,'stroke-width':2,'stroke-opacity':dim?0.4:0.9,'stroke-linejoin':'round'},gProf);
   circ.forEach(function(c,j){
     var t0=t0s[j],yv=Yv(val(t0));
     mk('line',{x1:Xt(t0),y1:yBase,x2:Xt(t0),y2:yv,stroke:c.c,'stroke-width':2,'stroke-dasharray':'4 3',opacity:dim?0.5:1},gPk);
     mk('line',{x1:Xt(t0),y1:yBase,x2:Xt(t0),y2:yBase+6,stroke:c.c,'stroke-width':2.4},gPk);
     mk('circle',{cx:Xt(t0),cy:yv,r:5,fill:c.c,stroke:'#fff','stroke-width':1.4,opacity:dim?0.5:1},gPk);
     tx({x:Xt(t0),y:yv-9,'font-size':12.5,'font-weight':700,fill:c.c,'text-anchor':'middle',opacity:dim?0.5:1},c.n,gPk);
   });
 }

 function drawAccum(count){
   clr(gAccum);
   for(var v=0;v<count;v++){
     var deg=v*DA, th=deg*DEG;
     var g=mk('g',{transform:'translate('+P3x+' '+P3y+') rotate('+(-deg)+')'},gAccum);
     circ.forEach(function(c){var t0=tval(c,th);mk('rect',{x:t0-13,y:-150,width:26,height:300,fill:'#ffffff',opacity:0.15},g);});
   }
 }
 function drawHi(idx){
   clr(gHi);
   if(idx<0)return;
   var deg=idx*DA, th=deg*DEG;
   var g=mk('g',{transform:'translate('+P3x+' '+P3y+') rotate('+(-deg)+')'},gHi);
   circ.forEach(function(c){var t0=tval(c,th);mk('rect',{x:t0-13,y:-150,width:26,height:300,fill:YEL,opacity:0.85},g);});
 }

 function updBtns(curIdx,count){
   for(var i=0;i<NV;i++){var b=btns[i];
     if(i===curIdx){b.r.setAttribute('fill',YEL);b.r.setAttribute('stroke',AMB);b.t.setAttribute('fill',INK);}
     else if(i<count){b.r.setAttribute('fill',GREEN);b.r.setAttribute('stroke',GD);b.t.setAttribute('fill','#ffffff');}
     else{b.r.setAttribute('fill','#ffffff');b.r.setAttribute('stroke',GL);b.t.setAttribute('fill',GREEN);}
   }
 }

 // ---------- state ----------
 function update(){
   var done=state===13, prep=state===0;
   var count=Math.min(state,NV);
   var curIdx=(state>=1&&state<=NV)?state-1:-1;
   var dispIdx=prep?0:(done?NV-1:state-1);
   var deg=dispIdx*DA;
   drawBeam(dispIdx,done);
   drawProfile(dispIdx,done);
   updBtns(curIdx,count);
   drawAccum(count);
   drawHi(curIdx);
   a1.textContent=prep?('θ = 0°（準備）'):(done?'完成（165°まで）':'θ = '+deg+'°');
   a2.textContent=done?'θ = 165°':'θ = '+deg+'°';
   p3count.textContent='加算 '+count+' / '+NV;
   var vn=prep?'準備':(done?'完成':String(state));
   var ang=prep?'0°（準備）':(done?'—':deg+'°');
   readout.textContent='ビュー '+vn+' ／ '+NV+'　｜　角度 '+ang+'　｜　加算済み '+count+' ／ '+NV+' ビュー';
   p3status.textContent=prep?'クリックして 0° を加算します':(done?'完成：2つの円が明るく、放射状にぼけた逆投影画像':'現在のビュー（θ='+deg+'°）の帯を黄色で加算');
 }
 function setState(s){state=Math.max(0,Math.min(13,s));update();}

 window.addEventListener('keydown',function(e){
   var k=e.key;
   if(k==='ArrowRight'||k==='ArrowDown'||k===' '||k==='Enter'){e.preventDefault();setState(state+1);}
   else if(k==='ArrowLeft'||k==='ArrowUp'){e.preventDefault();setState(state-1);}
   else if(k==='r'||k==='R'){e.preventDefault();setState(0);}
 });

 setState(0);
})();
